17→/**
18→ * Lint and format the spacing between the modifiers in and after the last modifier in a modifier list.
19→ */
20→public class ModifierListSpacingRule : Rule("$EXPERIMENTAL_RULE_SET_ID:modifier-list-spacing") {
21→    override fun beforeVisitChildNodes(
22→        node: ASTNode,
23→        autoCorrect: Boolean,
24→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
25→    ) {
26→        if (node.elementType == MODIFIER_LIST) {
27→            node
28→                .children()
29→                .forEach { visitModifierChild(it, autoCorrect, emit) }
30→            // The whitespace of the last entry of the modifier list is actually placed outside the modifier list
31→            visitModifierChild(node, autoCorrect, emit)
32→        }
33→    }
34→
35→    private fun visitModifierChild(
36→        node: ASTNode,
37→        autoCorrect: Boolean,
38→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
39→    ) {
40→        if (node.elementType == WHITE_SPACE) {
41→            return
42→        }
43→        node.nextSibling { it.elementType == WHITE_SPACE && it.nextLeaf()?.isPartOfComment() != true }
44→            ?.takeIf { it.elementType == WHITE_SPACE }
45→            ?.takeUnless {
46→                // Regardless of element type, a single white space is always ok and does not need to be checked.
47→                it.text == " "
48→            }?.takeUnless {
49→                // A single newline after a comment is always ok and does not need further checking.
50→                it.text.trim(' ', '\t').contains('\n') && it.prevLeaf()?.isPartOfComment() == true
51→            }?.let { whitespace ->
52→                if (node.isAnnotationElement() ||
53→                    (node.elementType == MODIFIER_LIST && node.lastChildNode.isAnnotationElement())
54→                ) {
55→                    val expectedWhiteSpace = if (whitespace.textContains('\n')) {
56→                        "\n" + node.lineIndent()
57→                    } else {
58→                        " "
59→                    }
60→                    if (whitespace.text != expectedWhiteSpace) {
61→                        emit(
62→                            whitespace.startOffset,
63→                            "Single whitespace or newline expected after annotation",
64→                            true,
65→                        )
66→                        if (autoCorrect) {
67→                            (whitespace as LeafPsiElement).rawReplaceWithText(expectedWhiteSpace)
68→                        }
69→                    }
70→                } else {
71→                    emit(
72→                        whitespace.startOffset,
73→                        "Single whitespace expected after modifier",
74→                        true,
75→                    )
76→                    if (autoCorrect) {
77→                        (whitespace as LeafPsiElement).rawReplaceWithText(" ")
78→                    }
79→                }
80→            }
81→    }
82→
83→    private fun ASTNode?.isAnnotationElement() =
84→        this != null && (elementType == ANNOTATION || elementType == ANNOTATION_ENTRY)
85→}
